={
  "vectors": {
    "servico":[{{ $json.vector_servico }}],
    "produto":[{{ $json.vector_produto }}],
    "descricao":[{{ $json.vector_descricao }}],
    "publico":[{{ $json.vector_publico }}],
    "cliente":[{{ $json.vector_cliente }}]
  },
  "weights": {
    "servico": {{ $('AI Agent').item.json.output.peso_servicos }},
    "descricao": {{ $('AI Agent').item.json.output.peso_descricao }},
    "publico": {{ $('AI Agent').item.json.output.peso_publico }},
    "cliente": {{ $('AI Agent').item.json.output.peso_clientes }},
    "produto": {{ $('AI Agent').item.json.output.peso_produtos }},
    "bm25": {{ $('AI Agent').item.json.output.peso_bm25 }}

  },
  "filter": {
    "modelo_negocio": "{{ $('AI Agent').item.json.output.Modelo_Negocio }}"
  },
  "limit_per_vector": 10,
  "final_limit": 20,
  "bm25_query": "{{ $('AI Agent').item.json.output.bm25
  .replace(/[^\w\s\-.,]/g, '')
  .replace(/\s+/g, ' ')
  .trim()
}}"
}

